fn main() {
    let s = b"hello\x80"; // Latin-1 character
    for byte in s.iter() {
        println!("{}", *byte);
    }
}

fixed_code:
fn main() {
    let s = b"hello\x80"; // Latin-1 character
    for byte in s.iter() {
        println!("{:?}", *byte);
    }
}

