fn main() {
    let data = vec![235, 184, 169];
    let s = String::from_utf8(data).unwrap();
}

fixed_code:
fn main() {
    let data = vec![235, 184, 169];
    if let Ok(s) = String::from_utf8(data) {
        println!("{}", s);
    } else {
        eprintln!("Invalid UTF-8 sequence");
    }
}

